# Diagnostic test to check virtualenv bundled wheels integrity
describe "virtualenv bundled wheels diagnostic" do
  describe "Run diagnostic and save to file" do
    # First, run the diagnostic and save output to a file
    describe command("/opt/stackstorm/st2/bin/python -m virtualenv --version > /tmp/virtualenv-diagnostic.log 2>&1; echo '' >> /tmp/virtualenv-diagnostic.log; echo '========================================' >> /tmp/virtualenv-diagnostic.log; echo '  VIRTUALENV BUNDLED WHEELS DIAGNOSTIC' >> /tmp/virtualenv-diagnostic.log; echo '========================================' >> /tmp/virtualenv-diagnostic.log; echo '' >> /tmp/virtualenv-diagnostic.log; echo '1. Virtualenv Version:' >> /tmp/virtualenv-diagnostic.log; /opt/stackstorm/st2/bin/python -m virtualenv --version >> /tmp/virtualenv-diagnostic.log 2>&1 || echo '  ERROR: Could not determine virtualenv version' >> /tmp/virtualenv-diagnostic.log; echo '' >> /tmp/virtualenv-diagnostic.log; echo '2. Virtualenv Package Location:' >> /tmp/virtualenv-diagnostic.log; VENV_PKG=$(/opt/stackstorm/st2/bin/python -c 'import virtualenv; print(virtualenv.__file__)' 2>/dev/null); if [ -z \"$VENV_PKG\" ]; then echo '  ERROR: Could not locate virtualenv package' >> /tmp/virtualenv-diagnostic.log; else VENV_DIR=$(dirname \"$VENV_PKG\"); echo \"  Package dir: $VENV_DIR\" >> /tmp/virtualenv-diagnostic.log; echo '' >> /tmp/virtualenv-diagnostic.log; echo '3. Bundled Wheels Directory:' >> /tmp/virtualenv-diagnostic.log; WHEELS_DIR=\"$VENV_DIR/seed/wheels/embed\"; if [ -d \"$WHEELS_DIR\" ]; then echo \"  Location: $WHEELS_DIR\" >> /tmp/virtualenv-diagnostic.log; echo '  Contents:' >> /tmp/virtualenv-diagnostic.log; ls -lh \"$WHEELS_DIR\" 2>&1 | grep -E '\\.(whl|txt)$' >> /tmp/virtualenv-diagnostic.log || echo '  No .whl files found' >> /tmp/virtualenv-diagnostic.log; echo '' >> /tmp/virtualenv-diagnostic.log; echo '4. SHA256 Hashes of Key Bundled Wheels:' >> /tmp/virtualenv-diagnostic.log; for wheel in \"$WHEELS_DIR\"/pip-*.whl \"$WHEELS_DIR\"/setuptools-*.whl; do if [ -f \"$wheel\" ]; then BASENAME=$(basename \"$wheel\"); echo \"  File: $BASENAME\" >> /tmp/virtualenv-diagnostic.log; ACTUAL_HASH=$(sha256sum \"$wheel\" | awk '{print $1}'); echo \"    Actual SHA256: $ACTUAL_HASH\" >> /tmp/virtualenv-diagnostic.log; echo '' >> /tmp/virtualenv-diagnostic.log; fi; done; else echo \"  ERROR: Wheels directory not found at $WHEELS_DIR\" >> /tmp/virtualenv-diagnostic.log; fi; echo '' >> /tmp/virtualenv-diagnostic.log; echo '5. Virtualenv Cache Status:' >> /tmp/virtualenv-diagnostic.log; CACHE_DIR='/root/.cache/virtualenv'; if [ -d \"$CACHE_DIR\" ]; then echo \"  Cache location: $CACHE_DIR\" >> /tmp/virtualenv-diagnostic.log; CACHE_SIZE=$(du -sh \"$CACHE_DIR\" 2>/dev/null | awk '{print $1}'); echo \"  Cache size: $CACHE_SIZE\" >> /tmp/virtualenv-diagnostic.log; else echo '  No cache found at $CACHE_DIR' >> /tmp/virtualenv-diagnostic.log; fi; fi; echo '' >> /tmp/virtualenv-diagnostic.log; echo '========================================' >> /tmp/virtualenv-diagnostic.log; echo '  DIAGNOSTIC COMPLETE' >> /tmp/virtualenv-diagnostic.log; echo '========================================' >> /tmp/virtualenv-diagnostic.log; cat /tmp/virtualenv-diagnostic.log") do
      its(:exit_status) { is_expected.to eq 0 }
    end

    # Then verify the diagnostic file was created
    describe file('/tmp/virtualenv-diagnostic.log') do
      it { should be_file }
      its(:content) { should match /DIAGNOSTIC COMPLETE/ }
    end
  end
end